import React, { useEffect } from "react";
import {
  Leaf,
  Award,
  Cpu,
  Heart,
  Star,
  Cookie,
  CheckCircle2,
} from "lucide-react";
import "./AboutUs2.css";

/* ================== البيانات ================== */

const COMPANY_INFO = {
  founded: "2023",
  story_title: "حكاية تأسيس بيسكوزا",
  story_text_1:
    "شركة سورية متخصصة في صناعة البسكويت تأسست عام 2023 بشغف كبير لتقديم منتجات عالية الجودة.",
  story_text_2:
    "نحرص على استخدام أجود المكونات لإنتاج أصناف مميزة تضيف لحظات من السعادة.",
  quality_text:
    "نلتزم بأعلى معايير الجودة العالمية باستخدام خطوط إنتاج مؤتمتة بالكامل.",
};

const FEATURES = [
  {
    title: "أجود المكونات",
    description: "مكونات طبيعية مختارة بعناية.",
    icon: <Leaf />,
  },
  {
    title: "تكنولوجيا متطورة",
    description: "إنتاج مؤتمت بالكامل.",
    icon: <Cpu />,
  },
  {
    title: "جودة عالمية",
    description: "معايير عالمية في التصنيع.",
    icon: <Award />,
  },
  {
    title: "شغفنا السعادة",
    description: "نسعى لرسم الابتسامة.",
    icon: <Heart />,
  },
];

/* ================== Sections ================== */

const Hero = () => (
  <section className="hero-section fade-up">
    <div className="aboutus-container hero-content">
      <div className="hero-grid">
        <div className="hero-text">
          <div className="badge">
            <Star size={16} fill="currentColor" />
            <span>قصة نجاح منذ {COMPANY_INFO.founded}</span>
          </div>

          <h1 className="hero-title">
            طعم يأخذك إلى <br />
            <span className="hero-title-highlight">عالم السعادة</span>
          </h1>

          <p className="hero-description">
            نمزج الشغف بأجود المكونات لنقدم بسكويت بطعم لا يُنسى.
          </p>

          <button className="btn-primary btn-lg">
            <Cookie size={20} />
            <span className="taste">تذوق منتجاتنا</span>
          </button>
        </div>

        <div className="hero-img-container">
          <img
            src="/images/Huggy.webp"
            alt="Biscoza"
            className="hero-main-img"
          />

          <div className="floating-card card-bottom">
            <div className="card-header">
              <CheckCircle2 size={15} color="red" />
              <span className="card-text">طعم لا يقاوم</span>
            </div>
            <div className="progress-bar"></div>
          </div>
        </div>
      </div>
    </div>
  </section>
);

const StorySection = () => (
  <section className="story-section fade-up delay-1">
    <div className="aboutus-container story-grid">
      <div className="story-content">
        <h2 className="section-title">{COMPANY_INFO.story_title}</h2>
        <p className="story-intro">{COMPANY_INFO.story_text_1}</p>
        <p>{COMPANY_INFO.story_text_2}</p>
      </div>

      <div className="story-img-container">
        <img src="/images/dishleft.webp" className="story-img" alt="story" />
      </div>
    </div>
  </section>
);

const QuoteSection = () => (
  <section className="quote-section fade-up delay-2">
    <h2 className="quote-text">"قطعة بسكويت قد تكون سبباً لسعادة يومك"</h2>
  </section>
);

const QualitySection = () => (
  <section className="quality-section fade-up delay-3">
    <div className="aboutus-container">
      <h2 className="section-title">
        التزامنا <span className="text-red">بالجودة</span>
      </h2>

      <p className="section-desc">{COMPANY_INFO.quality_text}</p>

      <div className="features-grid">
        {FEATURES.map((item, i) => (
          <div key={i} className="feature-card">
            <div className="feature-icon-wrapper">
              {React.cloneElement(item.icon, { className: "feature-icon" })}
            </div>
            <h3>{item.title}</h3>
            <p>{item.description}</p>
          </div>
        ))}
      </div>
    </div>
  </section>
);

/* ================== Main ================== */

export default function AboutUs() {
  useEffect(() => {
    document
      .querySelectorAll(".fade-up")
      .forEach((el) => el.classList.add("show"));
  }, []);

  return (
    <div className="app-root">
      <Hero />
      <StorySection />
      <QuoteSection />
      <QualitySection />
    </div>
  );
}
